#!/usr/bin/env node
/**
 * Archive OCI Orphan Files
 *
 * Moves orphan files (in OCI but not in MongoDB) to an archive bucket.
 * Reads from an audit report JSON file generated by audit-mongodb-oci-sync.js
 *
 * Production-Ready Features:
 * - Dry-run mode by default (requires --apply to execute)
 * - Copies to archive bucket, then deletes from source
 * - Progress tracking and detailed logging
 * - Graceful error handling with retry logic
 * - Clean text-based logging for log aggregation
 *
 * Usage:
 *   node scripts/archive-oci-orphans.js --report audit-report.json
 *   node scripts/archive-oci-orphans.js --report audit-report.json --apply
 *   node scripts/archive-oci-orphans.js --report audit-report.json --apply --archive-bucket wurud-archive
 *
 * Options:
 *   --report <file>          Audit report JSON file (required)
 *   --archive-bucket <name>  Target archive bucket (default: wurud-archive)
 *   --apply                  Actually move files (default is dry-run)
 *   --keep-source            Don't delete from source after copying
 *   --limit N                Process only first N files (for testing)
 *   --verbose                Show detailed progress
 */

require('dotenv').config();

const path = require('path');
const fs = require('fs');
const oci = require(path.join(__dirname, '..', 'config', 'oci'));

// Parse arguments
const args = process.argv.slice(2);
const DRY_RUN = !args.includes('--apply');
const KEEP_SOURCE = args.includes('--keep-source');
const VERBOSE = args.includes('--verbose');

function getArg(name) {
  const idx = args.indexOf(name);
  return idx !== -1 && args[idx + 1] && !args[idx + 1].startsWith('--')
    ? args[idx + 1]
    : null;
}

const REPORT_FILE = getArg('--report');
const ARCHIVE_BUCKET = getArg('--archive-bucket') || 'wurud-archive';
const LIMIT = getArg('--limit') ? parseInt(getArg('--limit')) : null;

if (!REPORT_FILE) {
  console.log(`
Usage: node scripts/archive-oci-orphans.js --report <audit-report.json> [options]

Required:
  --report <file>          Audit report JSON from audit-mongodb-oci-sync.js

Options:
  --archive-bucket <name>  Target archive bucket (default: wurud-archive)
  --apply                  Actually move files (default is dry-run)
  --keep-source            Don't delete from source after copying
  --limit N                Process only first N files (for testing)
  --verbose                Show detailed progress

Example:
  node scripts/archive-oci-orphans.js --report audit-report.json --apply
`);
  process.exit(1);
}

/**
 * Format bytes to human readable
 */
function formatBytes(bytes) {
  if (!bytes || bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
}

/**
 * Sleep helper for retry backoff
 */
function sleep(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

/**
 * Copy object to archive bucket with retry
 */
async function copyToArchive(client, namespace, sourceBucket, objectName, retries = 3) {
  const copyObjectRequest = {
    namespaceName: namespace,
    bucketName: ARCHIVE_BUCKET,
    copyObjectDetails: {
      sourceObjectName: objectName,
      destinationRegion: oci.getRegion(),
      destinationNamespace: namespace,
      destinationBucket: sourceBucket,
      destinationObjectName: objectName
    }
  };

  // Fix: source and destination are swapped in OCI SDK
  // We copy FROM sourceBucket TO ARCHIVE_BUCKET
  copyObjectRequest.copyObjectDetails.destinationBucket = ARCHIVE_BUCKET;
  copyObjectRequest.bucketName = sourceBucket;

  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      await client.copyObject(copyObjectRequest);
      return { success: true };
    } catch (error) {
      if (attempt < retries && (error.statusCode === 429 || error.statusCode >= 500)) {
        const delay = Math.pow(2, attempt) * 1000;
        console.log(`   [RETRY] Attempt ${attempt} failed, retrying in ${delay}ms...`);
        await sleep(delay);
      } else {
        throw error;
      }
    }
  }
}

/**
 * Delete object from source bucket with retry
 */
async function deleteFromSource(client, namespace, bucketName, objectName, retries = 3) {
  const deleteRequest = {
    namespaceName: namespace,
    bucketName: bucketName,
    objectName: objectName
  };

  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      await client.deleteObject(deleteRequest);
      return { success: true };
    } catch (error) {
      if (error.statusCode === 404) {
        return { success: true, note: 'Already deleted' };
      }
      if (attempt < retries && (error.statusCode === 429 || error.statusCode >= 500)) {
        const delay = Math.pow(2, attempt) * 1000;
        await sleep(delay);
      } else {
        throw error;
      }
    }
  }
}

/**
 * Main archive function
 */
async function archiveOrphans() {
  console.log('='.repeat(70));
  console.log('  ARCHIVE OCI ORPHAN FILES');
  console.log('='.repeat(70));
  console.log(`
  Mode:           ${DRY_RUN ? 'DRY RUN (use --apply to execute)' : 'LIVE'}
  Report:         ${REPORT_FILE}
  Archive Bucket: ${ARCHIVE_BUCKET}
  Keep Source:    ${KEEP_SOURCE ? 'Yes' : 'No (delete after copy)'}
  Limit:          ${LIMIT || 'None'}
`);

  // Read audit report
  if (!fs.existsSync(REPORT_FILE)) {
    console.error(`[ERROR] Report file not found: ${REPORT_FILE}`);
    process.exit(1);
  }

  console.log('[INFO] Reading audit report...');
  const report = JSON.parse(fs.readFileSync(REPORT_FILE, 'utf8'));

  const orphans = report.ociOrphans || [];
  if (orphans.length === 0) {
    console.log('[INFO] No OCI orphans found in report. Nothing to archive.');
    process.exit(0);
  }

  console.log(`[INFO] Found ${orphans.length} orphan files to archive\n`);

  // Apply limit if set
  const filesToProcess = LIMIT ? orphans.slice(0, LIMIT) : orphans;
  if (LIMIT) {
    console.log(`[INFO] Processing first ${LIMIT} files only\n`);
  }

  // Initialize OCI client
  const client = oci.client;
  if (!client) {
    console.error('[ERROR] OCI client not initialized. Check environment variables.');
    process.exit(1);
  }

  const namespace = oci.getNamespace();
  const sourceBucket = oci.getBucketName();

  console.log(`[INFO] Source bucket: ${sourceBucket}`);
  console.log(`[INFO] Archive bucket: ${ARCHIVE_BUCKET}\n`);

  // Check if archive bucket exists (try to list with limit 1)
  if (!DRY_RUN) {
    try {
      await client.listObjects({
        namespaceName: namespace,
        bucketName: ARCHIVE_BUCKET,
        limit: 1
      });
      console.log('[INFO] Archive bucket verified\n');
    } catch (error) {
      if (error.statusCode === 404) {
        console.error(`[ERROR] Archive bucket "${ARCHIVE_BUCKET}" does not exist.`);
        console.error('        Create it first in OCI Console or with OCI CLI.');
        process.exit(1);
      }
      throw error;
    }
  }

  // Process files
  const stats = {
    total: filesToProcess.length,
    copied: 0,
    deleted: 0,
    errors: 0,
    skipped: 0
  };

  console.log('-'.repeat(70));
  console.log('  Processing files...');
  console.log('-'.repeat(70));

  for (let i = 0; i < filesToProcess.length; i++) {
    const orphan = filesToProcess[i];
    const filename = orphan.filename;
    const progress = `[${i + 1}/${filesToProcess.length}]`;

    if (DRY_RUN) {
      console.log(`${progress} [DRY-RUN] Would archive: ${filename.substring(0, 60)}${filename.length > 60 ? '...' : ''}`);
      stats.copied++;
      continue;
    }

    try {
      // Copy to archive bucket
      if (VERBOSE) {
        console.log(`${progress} Copying: ${filename.substring(0, 50)}...`);
      }

      await copyToArchive(client, namespace, sourceBucket, filename);
      stats.copied++;

      // Delete from source (unless --keep-source)
      if (!KEEP_SOURCE) {
        await deleteFromSource(client, namespace, sourceBucket, filename);
        stats.deleted++;
      }

      if (VERBOSE) {
        console.log(`${progress} [OK] Archived: ${filename.substring(0, 50)}...`);
      } else if ((i + 1) % 10 === 0) {
        process.stdout.write(`\r   Processed ${i + 1}/${filesToProcess.length} files...`);
      }

    } catch (error) {
      stats.errors++;
      console.log(`${progress} [ERROR] ${filename.substring(0, 40)}: ${error.message}`);
    }
  }

  if (!DRY_RUN && !VERBOSE) {
    console.log(`\r   Processed ${filesToProcess.length}/${filesToProcess.length} files      `);
  }

  // Summary
  console.log('\n' + '='.repeat(70));
  console.log('  SUMMARY');
  console.log('='.repeat(70));
  console.log(`
  Total files:    ${stats.total}
  Copied:         ${stats.copied}
  Deleted:        ${stats.deleted}
  Errors:         ${stats.errors}
`);

  if (DRY_RUN) {
    console.log('[INFO] DRY RUN complete. No files were moved.');
    console.log('       Run with --apply to actually archive the files.\n');
  } else if (stats.errors === 0) {
    console.log('[SUCCESS] All files archived successfully!\n');
  } else {
    console.log(`[WARN] Completed with ${stats.errors} errors.\n`);
  }

  return stats;
}

// Main entry point with error handling
async function main() {
  try {
    await archiveOrphans();
  } catch (err) {
    console.error(`\n[ERROR] Archive failed: ${err.message}`);
    if (VERBOSE) {
      console.error(err.stack);
    }
    process.exit(1);
  }
}

main();
